1312 // Helper to generate an ordered reduction.
1313 Value *llvm::getOrderedReduction(IRBuilderBase &Builder, Value *Acc, Value *Src,
1314                                  unsigned Op, RecurKind RdxKind) {
1315   unsigned VF = cast<FixedVectorType>(Src->getType())->getNumElements();
1316 
1317   // Extract and apply reduction ops in ascending order:
1318   // e.g. ((((Acc + Scl[0]) + Scl[1]) + Scl[2]) + ) ... + Scl[VF-1]
1319   Value *Result = Acc;
1320   for (unsigned ExtractIdx = 0; ExtractIdx != VF; ++ExtractIdx) {
1321     Value *Ext =
1322         Builder.CreateExtractElement(Src, Builder.getInt32(ExtractIdx));
1323 
1324     if (Op != Instruction::ICmp && Op != Instruction::FCmp) {
1325       Result = Builder.CreateBinOp((Instruction::BinaryOps)Op, Result, Ext,
1326                                    "bin.rdx");
1327     } else {
1328       assert(RecurrenceDescriptor::isMinMaxRecurrenceKind(RdxKind) &&
1329              "Invalid min/max");
1330       Result = createMinMaxOp(Builder, RdxKind, Result, Ext);
1331     }
1332   }
1333 
1334   return Result;
1335 }
