1258 std::optional<RecurrenceDescriptor>
1259 llvm::canParallelizeReductionWhenUnrolling(PHINode &Phi, Loop *L,
1260                                            ScalarEvolution *SE) {
1261   RecurrenceDescriptor RdxDesc;
1262   if (!RecurrenceDescriptor::isReductionPHI(&Phi, L, RdxDesc,
1263                                             /*DemandedBits=*/nullptr,
1264                                             /*AC=*/nullptr, /*DT=*/nullptr, SE))
1265     return std::nullopt;
1266   if (RdxDesc.hasUsesOutsideReductionChain())
1267     return std::nullopt;
1268   RecurKind RK = RdxDesc.getRecurrenceKind();
1269   // Skip unsupported reductions. Min/max (integer and FP) are supported.
1270   // TODO: Handle additional reductions.
1271   if (RecurrenceDescriptor::isAnyOfRecurrenceKind(RK) ||
1272       RecurrenceDescriptor::isFindRecurrenceKind(RK))
1273     return std::nullopt;
1274 
1275   if (RdxDesc.hasExactFPMath())
1276     return std::nullopt;
1277 
1278   if (RdxDesc.IntermediateStore)
1279     return std::nullopt;
1280 
1281   // Don't unroll reductions with constant ops; those can be folded to a
1282   // single induction update.
1283   if (any_of(cast<Instruction>(Phi.getIncomingValueForBlock(L->getLoopLatch()))
1284                  ->operands(),
1285              IsaPred<Constant>))
1286     return std::nullopt;
1287 
1288   BasicBlock *Latch = L->getLoopLatch();
1289   if (!Latch ||
1290       !is_contained(
1291           cast<Instruction>(Phi.getIncomingValueForBlock(Latch))->operands(),
1292           &Phi))
1293     return std::nullopt;
1294 
1295   return RdxDesc;
1296 }
