1322         Builder.CreateExtractElement(Src, Builder.getInt32(ExtractIdx));
1323 
1324     if (Op != Instruction::ICmp && Op != Instruction::FCmp) {
1325       Result = Builder.CreateBinOp((Instruction::BinaryOps)Op, Result, Ext,
1326                                    "bin.rdx");
1327     } else {
1328       assert(RecurrenceDescriptor::isMinMaxRecurrenceKind(RdxKind) &&
1329              "Invalid min/max");
1330       Result = createMinMaxOp(Builder, RdxKind, Result, Ext);
1331     }
1332   }
1333 
1334   return Result;
1335 }
