1532          "Unexpected reduction kind");
1533   assert(Src->getType()->isVectorTy() && "Expected a vector type");
1534   assert(!Start->getType()->isVectorTy() && "Expected a scalar type");
1535 
1536   return B.CreateFAddReduce(Start, Src);
